// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract MyContract {
    // Replace this with your actual deployed MathsContract address
    address constant MATH_CONTRACT_ADDRESS = 0x08453E0787F0399eD9f1BD16CeEc37D23F230430;

    function useAdd(uint256 a, uint256 b) public view returns (uint256) {
        (bool success, bytes memory returnData) = MATH_CONTRACT_ADDRESS.staticcall(
            abi.encodeWithSignature("add(uint256,uint256)", a, b)
        );

        require(success, "Staticcall to add() failed");
        return abi.decode(returnData, (uint256));
    }

    function useMul(uint256 a, uint256 b) public view returns (uint256) {
        (bool success, bytes memory returnData) = MATH_CONTRACT_ADDRESS.staticcall(
            abi.encodeWithSignature("mul(uint256,uint256)", a, b)
        );

        require(success, "Staticcall to mul() failed");
        return abi.decode(returnData, (uint256));
    }

    // Add more like useSub, useDiv if needed
}

